import { useEffect, useMemo, useState } from 'react';
import { ActivityIndicator, Image, Linking, Platform, Pressable, SafeAreaView, ScrollView, StyleSheet, Text, TextInput, View } from 'react-native';
import { autoApproveGptReady, loadOperatorDashboard, loadResearchLeads, operatorLogin, operatorLogout, processResearchLeads, saveAutopilotPolicy, submitOperatorReview, syncApprovedPhotos, type AutopilotPolicy, type OperatorDashboard, type OperatorSubmission, type ResearchLead, type ResearchLeads, type ReviewDecision } from '../lib/operatorApi';

type QueueTab = 'judgment' | 'approved' | 'operatorApproved' | 'rejected' | 'research';
type EntityFilter = 'all' | 'place_suggestion' | 'restroom_update' | 'research_lead';
type RejectionFilter = 'all' | 'gpt' | 'operator';

const tabLabels: Record<QueueTab, string> = { judgment: 'Needs judgment', approved: 'GPT approved', operatorApproved: 'Operator approved', rejected: 'Rejected', research: 'Research leads' };
const decisionLabel = (decision: ReviewDecision) => decision === 'eligible_for_human_publish' ? 'GPT approved' : decision === 'reject' ? 'Rejected' : decision === 'needs_human_review' ? 'Needs judgment' : 'Awaiting GPT';
const dateLabel = (value: string) => new Date(value).toLocaleString([], { month: 'short', day: 'numeric', hour: 'numeric', minute: '2-digit' });
const entityLabel = (type: OperatorSubmission['entityType']) => type === 'place_suggestion' ? 'Suggestion' : type === 'restroom_update' ? 'Update' : 'Research lead';
const operatorRejected = (row: OperatorSubmission) => Boolean(row.aiReview?.operator_actions?.some((action) => action.actor === 'operator' && action.action === 'rejected'));
const rejectionKind = (row: OperatorSubmission) => operatorRejected(row) ? 'Operator rejected' : 'GPT auto-rejected';
const displayTag = (tag: string) => tag.replaceAll('_', ' ');

export default function OperatorConsole() {
  const [password, setPassword] = useState('');
  const [dashboard, setDashboard] = useState<OperatorDashboard | null>(null);
  const [research, setResearch] = useState<ResearchLeads | null>(null);
  const [tab, setTab] = useState<QueueTab>('judgment');
  const [entityFilter, setEntityFilter] = useState<EntityFilter>('all');
  const [rejectionFilter, setRejectionFilter] = useState<RejectionFilter>('all');
  const [selected, setSelected] = useState<OperatorSubmission | null>(null);
  const [showTrace, setShowTrace] = useState(false);
  const [loading, setLoading] = useState(true);
  const [authenticating, setAuthenticating] = useState(false);
  const [actioning, setActioning] = useState(false);
  const [error, setError] = useState('');
  const [notice, setNotice] = useState('');

  const refresh = async () => { setLoading(true); setError(''); try { const [nextDashboard, nextResearch] = await Promise.all([loadOperatorDashboard(), loadResearchLeads()]); setDashboard(nextDashboard); setResearch(nextResearch); const photoSync = await syncApprovedPhotos().catch(() => ({ ok: false, promoted: 0 })); if (photoSync.promoted > 0) setNotice(`${photoSync.promoted} approved restroom photo${photoSync.promoted === 1 ? '' : 's'} published to the map.`); } catch (cause) { setDashboard(null); setResearch(null); setError(cause instanceof Error ? cause.message : 'Could not load operator data.'); } finally { setLoading(false); } };
  useEffect(() => { refresh(); }, []);
  const login = async () => { if (!password.trim()) return setError('Enter the shared demo password.'); setAuthenticating(true); setError(''); try { await operatorLogin(password); await refresh(); } catch (cause) { setError(cause instanceof Error ? cause.message : 'Could not unlock the operator workspace.'); } finally { setAuthenticating(false); } };
  const saveReview = async (action: 'approve' | 'reject' | 'edit_and_requeue', note?: string) => { if (!selected) return; setActioning(true); setNotice(''); setError(''); try { const result = await submitOperatorReview(selected.entityType, selected.id, action, note); setNotice(result.message); setSelected(null); await refresh(); } catch (cause) { setError(cause instanceof Error ? cause.message : 'Could not save the review.'); } finally { setActioning(false); } };
  const autoApprove = async () => { setActioning(true); setNotice(''); setError(''); try { const result = await autoApproveGptReady(); setNotice(result.message); await refresh(); } catch (cause) { setError(cause instanceof Error ? cause.message : 'Could not auto-approve the GPT-approved queue.'); } finally { setActioning(false); } };
  const updateAutopilot = async (enabled: boolean, confidenceThreshold: number) => { setActioning(true); setNotice(''); setError(''); try { const policy = await saveAutopilotPolicy(enabled, confidenceThreshold); setDashboard((current) => current ? { ...current, autopilot: policy } : current); setNotice(policy.enabled ? `Autopilot is on at ${Math.round(policy.confidenceThreshold * 100)}%.` : 'Autopilot is off. New submissions will stay in review.'); } catch (cause) { setError(cause instanceof Error ? cause.message : 'Could not save the autopilot policy.'); } finally { setActioning(false); } };
  const processLeads = async (ids?: string[]) => { setActioning(true); setNotice(''); setError(''); try { const result = await processResearchLeads(ids); setNotice(result.message); const [nextDashboard, nextResearch] = await Promise.all([loadOperatorDashboard(), loadResearchLeads()]); setDashboard(nextDashboard); setResearch(nextResearch); setTab('judgment'); } catch (cause) { setError(cause instanceof Error ? cause.message : 'Could not process research leads.'); } finally { setActioning(false); } };
  const leave = async () => { try { await operatorLogout(); } finally { setDashboard(null); setPassword(''); setSelected(null); } };

  if (loading) return <Screen><View style={styles.center}><ActivityIndicator color="#C95B34" /><Text style={styles.muted}>Loading operator review…</Text></View></Screen>;
  if (!dashboard) return <Login password={password} setPassword={setPassword} login={login} authenticating={authenticating} error={error} />;
  const activeRows = tab === 'judgment' ? dashboard.needsJudgment : tab === 'approved' ? dashboard.gptApproved : tab === 'operatorApproved' ? dashboard.operatorApproved : dashboard.rejected;
  const rows = entityFilter === 'all' ? activeRows : activeRows.filter((row) => row.entityType === entityFilter);
  const filteredRows = tab !== 'rejected' || rejectionFilter === 'all' ? rows : rows.filter((row) => rejectionFilter === 'gpt' ? !operatorRejected(row) : operatorRejected(row));
  const tabCount = (kind: QueueTab) => kind === 'judgment' ? dashboard.stats.needsJudgment : kind === 'approved' ? dashboard.stats.gptApproved : kind === 'operatorApproved' ? dashboard.stats.operatorApproved : kind === 'rejected' ? dashboard.stats.gptRejected : research?.stats.total || dashboard.stats.candidateLeads;

  return <Screen>
    <Header onRefresh={refresh} onTrace={() => setShowTrace(true)} onLock={leave} />
    <ScrollView contentContainerStyle={styles.content} showsVerticalScrollIndicator={false}>
      <Text style={styles.pageTitle}>Operator Review</Text>
      <View style={styles.stats}><Stat value={dashboard.stats.needsJudgment} label="needs judgment" tone="dark" /><Stat value={dashboard.stats.gptApproved} label="GPT approved" /><Stat value={dashboard.stats.operatorApproved} label="operator approved" /><Stat value={dashboard.stats.published} label="published to map" /><Pressable style={styles.leadStat} onPress={() => setNotice(`${dashboard.stats.candidateLeads.toLocaleString()} research leads are private intake records. They are not published and have not entered GPT review yet.`)}><Text style={styles.statValue}>{dashboard.stats.candidateLeads.toLocaleString()}</Text><Text style={styles.statLabel}>research leads · not in review</Text></Pressable></View>
      <AutopilotControl policy={dashboard.autopilot} actioning={actioning} onChange={updateAutopilot} />
      {notice ? <View style={styles.notice}><Text style={styles.noticeText}>{notice}</Text></View> : null}{error ? <Text style={styles.error}>{error}</Text> : null}
      <View style={styles.queueBar}>{(Object.keys(tabLabels) as QueueTab[]).map((kind) => <Pressable key={kind} onPress={() => { setTab(kind); setEntityFilter('all'); setRejectionFilter('all'); }} style={[styles.queueTab, tab === kind && styles.queueTabActive]}><Text style={[styles.queueTabText, tab === kind && styles.queueTabTextActive]}>{tabLabels[kind]} <Text style={styles.count}>{tabCount(kind)}</Text></Text></Pressable>)}</View>
      {tab === 'research' ? <ResearchLedgerV2 research={research} actioning={actioning} onProcess={processLeads} /> : <><View style={styles.tableHeader}><View style={styles.filters}>{(['all', 'place_suggestion', 'restroom_update', 'research_lead'] as EntityFilter[]).map((filter) => <Pressable key={filter} onPress={() => setEntityFilter(filter)} style={[styles.filterPill, entityFilter === filter && styles.filterPillActive]}><Text style={[styles.filterText, entityFilter === filter && styles.filterTextActive]}>{filter === 'all' ? 'All records' : entityLabel(filter)}</Text></Pressable>)}{tab === 'rejected' ? <><Pressable onPress={() => setRejectionFilter('gpt')} style={[styles.filterPill, rejectionFilter === 'gpt' && styles.filterPillActive]}><Text style={[styles.filterText, rejectionFilter === 'gpt' && styles.filterTextActive]}>GPT auto-rejected</Text></Pressable><Pressable onPress={() => setRejectionFilter('operator')} style={[styles.filterPill, rejectionFilter === 'operator' && styles.filterPillActive]}><Text style={[styles.filterText, rejectionFilter === 'operator' && styles.filterTextActive]}>Operator rejected</Text></Pressable></> : null}</View>{tab === 'approved' && <Pressable style={[styles.autoButton, !dashboard.stats.gptApproved && styles.buttonDisabled]} disabled={!dashboard.stats.gptApproved || actioning} onPress={autoApprove}><Text style={styles.autoButtonText}>{actioning ? 'Approving…' : `Auto approve all (${dashboard.stats.gptApproved})`}</Text></Pressable>}</View><LedgerV2 rows={filteredRows} tab={tab} onSelect={setSelected} /></>}
    </ScrollView>
    {selected ? <DetailDrawerV2 row={selected} actioning={actioning} onClose={() => setSelected(null)} onReview={saveReview} /> : null}
    {showTrace ? <TraceDrawerV2 rows={dashboard.audit} onClose={() => setShowTrace(false)} /> : null}
  </Screen>;
}

function Login({ password, setPassword, login, authenticating, error }: { password: string; setPassword: (value: string) => void; login: () => void; authenticating: boolean; error: string }) { return <Screen><View style={styles.loginWrap}><Text style={styles.loginTitle}>Operator Review</Text><Text style={styles.loginCopy}>Enter the shared demo password to open the private moderation workspace.</Text><TextInput value={password} onChangeText={setPassword} placeholder="Operator password" placeholderTextColor="#758279" secureTextEntry style={styles.passwordInput} onSubmitEditing={login} /><Pressable style={styles.primaryButton} onPress={login} disabled={authenticating}><Text style={styles.primaryButtonText}>{authenticating ? 'Unlocking…' : 'Unlock workspace'}</Text></Pressable>{error ? <Text style={styles.error}>{error}</Text> : null}<Pressable onPress={() => { if (Platform.OS === 'web' && typeof window !== 'undefined') window.location.assign('/'); }}><Text style={styles.backLink}>← Back to public map</Text></Pressable></View></Screen>; }
function Screen({ children }: { children: React.ReactNode }) { return <SafeAreaView style={styles.screen}>{children}</SafeAreaView>; }
function Header({ onRefresh, onTrace, onLock }: { onRefresh: () => void; onTrace: () => void; onLock: () => void }) { return <View style={styles.header}><View><Text style={styles.wordmark}>RELIEF</Text><Text style={styles.headerSub}>Private operator workspace · San Francisco</Text></View><View style={styles.headerActions}><Pressable onPress={onTrace} style={styles.headerButton}><Text style={styles.headerButtonText}>Activity</Text></Pressable><Pressable onPress={onRefresh} style={styles.headerButton}><Text style={styles.headerButtonText}>Refresh</Text></Pressable><Pressable onPress={onLock} style={styles.headerButton}><Text style={styles.headerButtonText}>Lock</Text></Pressable></View></View>; }
function Stat({ value, label, tone }: { value: string | number; label: string; tone?: 'dark' }) { return <View style={[styles.stat, tone === 'dark' && styles.statDark]}><Text style={[styles.statValue, tone === 'dark' && styles.statValueDark]}>{value}</Text><Text style={[styles.statLabel, tone === 'dark' && styles.statLabelDark]}>{label}</Text></View>; }
function AutopilotControl({ policy, actioning, onChange }: { policy: AutopilotPolicy; actioning: boolean; onChange: (enabled: boolean, threshold: number) => void }) {
  const thresholdOptions = [0.9, 0.92, 0.95];
  return <View style={[styles.autopilotCard, policy.enabled && styles.autopilotCardEnabled]}><View style={styles.autopilotIntro}><View><Text style={styles.autopilotEyebrow}>GPT-5.6 AUTOPILOT</Text><Text style={styles.autopilotTitle}>{policy.enabled ? 'Publishing eligible photo submissions' : 'Held for operator release'}</Text><Text style={styles.autopilotCopy}>Only a restroom photo, no safety concerns, a valid place, and a qualifying GPT decision can pass. Research leads never qualify.</Text></View><Pressable style={[styles.autopilotToggle, policy.enabled && styles.autopilotToggleOn, (!policy.configured || actioning) && styles.buttonDisabled]} disabled={!policy.configured || actioning} onPress={() => onChange(!policy.enabled, policy.confidenceThreshold)}><View style={[styles.autopilotKnob, policy.enabled && styles.autopilotKnobOn]} /><Text style={[styles.autopilotToggleText, policy.enabled && styles.autopilotToggleTextOn]}>{policy.enabled ? 'On' : 'Off'}</Text></Pressable></View><View style={styles.autopilotControls}><Text style={styles.autopilotLabel}>CONFIDENCE FLOOR</Text>{thresholdOptions.map((threshold) => <Pressable key={threshold} style={[styles.thresholdPill, policy.confidenceThreshold === threshold && styles.thresholdPillActive, (!policy.configured || actioning) && styles.buttonDisabled]} disabled={!policy.configured || actioning} onPress={() => onChange(policy.enabled, threshold)}><Text style={[styles.thresholdText, policy.confidenceThreshold === threshold && styles.thresholdTextActive]}>{Math.round(threshold * 100)}%</Text></Pressable>)}<Text style={styles.autopilotStatus}>{policy.configured ? policy.enabled ? 'Eligible submissions publish immediately.' : 'Toggle on for a live autopilot demo.' : 'Run the autopilot policy SQL once to enable controls.'}</Text></View></View>;
}
function Ledger({ rows, tab, onSelect }: { rows: OperatorSubmission[]; tab: QueueTab; onSelect: (row: OperatorSubmission) => void }) { if (!rows.length) return <View style={styles.empty}><Text style={styles.emptyTitle}>{tab === 'approved' ? 'No GPT-approved records' : tab === 'rejected' ? 'No rejected records' : 'Nothing needs judgment'}</Text><Text style={styles.emptyCopy}>{tab === 'approved' ? 'High-confidence submissions will be ready here for a batch publish.' : tab === 'rejected' ? 'Rejected evidence remains visible here if you need to amend and re-run it.' : 'New submissions appear here only when GPT needs a person to decide.'}</Text></View>; return <View style={styles.ledger}><View style={styles.columnHeaders}><Text style={[styles.columnLabel, styles.colPhoto]}>PHOTO</Text><Text style={[styles.columnLabel, styles.colRecord]}>RECORD</Text><Text style={[styles.columnLabel, styles.colType]}>TYPE</Text><Text style={[styles.columnLabel, styles.colConfidence]}>CONF.</Text><Text style={[styles.columnLabel, styles.colStatus]}>STATUS</Text></View>{rows.map((row) => <Pressable key={`${row.entityType}-${row.id}`} style={styles.ledgerRow} onPress={() => onSelect(row)}><View style={styles.colPhoto}>{row.photoUrl ? <Image source={{ uri: row.photoUrl }} style={styles.thumb} accessibilityLabel="Private restroom evidence thumbnail" /> : <View style={styles.thumbEmpty}><Text style={styles.thumbEmptyText}>—</Text></View>}</View><View style={styles.colRecord}><Text numberOfLines={1} style={styles.recordName}>{row.title}</Text><Text numberOfLines={1} style={styles.recordSub}>{row.subtitle}</Text></View><View style={styles.colType}><View style={[styles.typePill, row.entityType === 'place_suggestion' ? styles.suggestionPill : styles.updatePill]}><Text style={styles.typePillText}>{entityLabel(row.entityType)}</Text></View></View><Text style={styles.colConfidence}>{row.aiReview?.confidence != null ? `${Math.round(row.aiReview.confidence * 100)}%` : '—'}</Text><View style={styles.colStatus}><Text style={styles.statusText}>{row.aiReviewStatus === 'error' ? 'Review error' : decisionLabel(row.aiReview?.decision || null)}</Text><Text style={styles.inspect}>Open →</Text></View></Pressable>)}</View>; }
function ResearchLedger({ research, actioning, onProcess }: { research: ResearchLeads | null; actioning: boolean; onProcess: () => void }) { if (!research) return <View style={styles.empty}><Text style={styles.emptyTitle}>Research intake unavailable</Text><Text style={styles.emptyCopy}>Refresh the operator workspace to load the private source queue.</Text></View>; const sourceLabel = (lead: ResearchLead) => lead.source_name === 'OpenStreetMap' ? 'OpenStreetMap' : lead.source_name; return <View style={styles.researchWrap}><View style={styles.researchIntro}><View><Text style={styles.researchTitle}>Source triage</Text><Text style={styles.researchCopy}>GPT-5.6 routes source leads for evidence collection. It never verifies or publishes a restroom from open-data alone.</Text></View><Pressable style={[styles.processButton, (!research.stats.remaining || actioning) && styles.buttonDisabled]} disabled={!research.stats.remaining || actioning} onPress={onProcess}><Text style={styles.processButtonText}>{actioning ? 'Processing 100…' : `Process next 100 (${research.stats.remaining.toLocaleString()} left)`}</Text></Pressable></View><View style={styles.researchStats}><MiniStat value={research.stats.total.toLocaleString()} label="source leads" /><MiniStat value={research.stats.triaged.toLocaleString()} label="GPT triaged" /><MiniStat value={research.stats.rejected.toLocaleString()} label="source rejected" /></View><View style={styles.researchTable}><View style={styles.researchColumns}><Text style={[styles.columnLabel, styles.researchName]}>LEAD</Text><Text style={[styles.columnLabel, styles.researchSource]}>SOURCE</Text><Text style={[styles.columnLabel, styles.researchRoute]}>GPT ROUTE</Text><Text style={[styles.columnLabel, styles.researchConfidence]}>CONF.</Text></View>{research.leads.map((lead) => <View key={lead.id} style={styles.researchRow}><View style={styles.researchName}><Text numberOfLines={1} style={styles.recordName}>{lead.name}</Text><Text numberOfLines={1} style={styles.recordSub}>{lead.address || lead.venue_type}</Text></View><Pressable style={styles.researchSource} disabled={!lead.source_url} onPress={() => lead.source_url && Linking.openURL(lead.source_url)}><Text numberOfLines={1} style={[styles.sourceLink, !lead.source_url && styles.sourcePlain]}>{sourceLabel(lead)}{lead.source_url ? ' ↗' : ''}</Text><Text numberOfLines={1} style={styles.sourceLicense}>{lead.source_license || 'source retained'}</Text></Pressable><View style={styles.researchRoute}><Text style={styles.routeText}>{lead.ai_proposal?.route === 'evidence_collection' ? 'Collect evidence' : lead.ai_proposal?.route === 'needs_judgment' ? 'Needs judgment' : lead.ai_proposal?.route === 'reject' ? 'Rejected' : 'Untriaged'}</Text><Text numberOfLines={1} style={styles.routeReason}>{lead.ai_proposal?.reason || 'Awaiting batch triage'}</Text></View><Text style={styles.researchConfidence}>{lead.ai_proposal?.confidence != null ? `${Math.round(lead.ai_proposal.confidence * 100)}%` : '—'}</Text></View>)}</View></View>; }
function MiniStat({ value, label }: { value: string; label: string }) { return <View style={styles.miniStat}><Text style={styles.miniValue}>{value}</Text><Text style={styles.miniLabel}>{label}</Text></View>; }
function DetailDrawer({ row, onClose, onReview, actioning }: { row: OperatorSubmission; onClose: () => void; onReview: (action: 'approve' | 'reject' | 'edit_and_requeue', note?: string) => void; actioning: boolean }) { const [note, setNote] = useState(row.note); const rejected = row.aiReview?.decision === 'reject'; const pending = row.status === 'pending'; return <View style={styles.drawerScrim}><Pressable style={StyleSheet.absoluteFill} onPress={onClose} /><ScrollView style={styles.drawer} contentContainerStyle={styles.drawerContent}><View style={styles.drawerTop}><View><Text style={styles.drawerType}>{entityLabel(row.entityType)}</Text><Text style={styles.drawerTitle}>{row.title}</Text><Text style={styles.drawerSub}>{row.subtitle}</Text></View><Pressable onPress={onClose} style={styles.closeButton}><Text style={styles.closeButtonText}>×</Text></Pressable></View><View style={styles.detailMeta}><View style={styles.detailMetric}><Text style={styles.detailMetricValue}>{row.aiReview?.confidence != null ? `${Math.round(row.aiReview.confidence * 100)}%` : '—'}</Text><Text style={styles.detailMetricLabel}>GPT confidence</Text></View><View style={styles.detailMetric}><Text style={styles.detailMetricValue}>{decisionLabel(row.aiReview?.decision || null)}</Text><Text style={styles.detailMetricLabel}>GPT outcome</Text></View></View><View style={styles.evidenceGrid}><View style={styles.evidenceText}><Text style={styles.evidenceLabel}>GPT REASON</Text><Text style={styles.evidenceCopy}>{row.aiReview?.reason || row.aiReviewError || 'GPT has not returned an explanation yet.'}</Text>{row.aiReview?.description ? <><Text style={styles.evidenceLabel}>PROPOSED DESCRIPTION</Text><Text style={styles.evidenceCopy}>{row.aiReview.description}</Text></> : null}{row.aiReview?.concerns?.length ? <><Text style={styles.evidenceLabel}>CONCERNS</Text><Text style={styles.evidenceCopy}>{row.aiReview.concerns.join(' · ')}</Text></> : null}</View><View style={styles.photoFrame}>{row.photoUrl ? <Image source={{ uri: row.photoUrl }} style={styles.photo} resizeMode="cover" accessibilityLabel="Private contributor evidence" /> : <Text style={styles.photoEmpty}>No contributor photo</Text>}</View></View>{row.aiReview?.proposed_tags?.length ? <View style={styles.tagRow}>{row.aiReview.proposed_tags.map((tag) => <View key={tag} style={styles.tag}><Text style={styles.tagText}>{tag}</Text></View>)}</View> : null}{rejected && pending ? <View style={styles.editBlock}><Text style={styles.evidenceLabel}>AMEND AND RE-RUN GPT</Text><TextInput value={note} onChangeText={setNote} style={styles.noteInput} multiline placeholder="Correct the submitted detail before re-running" placeholderTextColor="#78847C" /><Pressable style={styles.secondaryButton} onPress={() => onReview('edit_and_requeue', note)} disabled={actioning}><Text style={styles.secondaryButtonText}>{actioning ? 'Saving…' : 'Save & re-run GPT review'}</Text></Pressable></View> : null}{pending && !rejected ? <View style={styles.reviewActions}><Pressable style={styles.rejectButton} onPress={() => onReview('reject')} disabled={actioning}><Text style={styles.rejectText}>Reject</Text></Pressable><Pressable style={styles.primaryButton} onPress={() => onReview('approve')} disabled={actioning}><Text style={styles.primaryButtonText}>{actioning ? 'Saving…' : row.entityType === 'place_suggestion' ? 'Publish to map' : 'Approve update'}</Text></Pressable></View> : null}{!pending ? <View style={styles.finalState}><Text style={styles.finalStateText}>{row.status === 'approved' ? 'This record is approved.' : 'This record is rejected.'}</Text></View> : null}</ScrollView></View>; }
function LedgerV2({ rows, tab, onSelect }: { rows: OperatorSubmission[]; tab: QueueTab; onSelect: (row: OperatorSubmission) => void }) {
  if (!rows.length) return <View style={styles.empty}><Text style={styles.emptyTitle}>{tab === 'approved' ? 'No GPT-approved records' : tab === 'rejected' ? 'No rejected records' : 'Nothing needs judgment'}</Text><Text style={styles.emptyCopy}>{tab === 'rejected' ? 'GPT and operator rejections stay here for audit or amendment.' : 'New submissions appear here when a person needs to decide.'}</Text></View>;
  return <View style={styles.ledger}><View style={styles.columnHeaders}><Text style={[styles.columnLabel, styles.colPhoto]}>PHOTO</Text><Text style={[styles.columnLabel, styles.colRecord]}>RECORD</Text><Text style={[styles.columnLabel, styles.colType]}>TYPE</Text><Text style={[styles.columnLabel, styles.colConfidence]}>CONF.</Text><Text style={[styles.columnLabel, styles.colStatus]}>STATUS</Text></View>{rows.map((row) => <Pressable key={`${row.entityType}-${row.id}`} style={styles.ledgerRow} onPress={() => onSelect(row)}><View style={styles.colPhoto}>{row.photoUrl ? <Image source={{ uri: row.photoUrl }} style={styles.thumb} accessibilityLabel="Private restroom evidence thumbnail" /> : <View style={styles.thumbEmpty}><Text style={styles.thumbEmptyText}>—</Text></View>}</View><View style={styles.colRecord}><Text numberOfLines={1} style={styles.recordName}>{row.title}</Text><Text numberOfLines={1} style={styles.recordSub}>{row.subtitle}</Text></View><View style={styles.colType}><View style={[styles.typePill, row.entityType === 'place_suggestion' ? styles.suggestionPill : styles.updatePill]}><Text style={styles.typePillText}>{entityLabel(row.entityType)}</Text></View></View><Text style={styles.colConfidence}>{row.aiReview?.confidence != null ? `${Math.round(row.aiReview.confidence * 100)}%` : '—'}</Text><View style={styles.colStatus}><Text style={styles.statusText}>{row.status === 'approved' ? row.aiReview?.operator_actions?.some((action) => action.actor === 'autopilot') ? 'GPT autopublished' : 'Operator approved' : row.status === 'rejected' ? 'Operator rejected' : row.aiReviewStatus === 'error' ? 'Review error' : decisionLabel(row.aiReview?.decision || null)}</Text><Text style={styles.inspect}>Open →</Text></View></Pressable>)}</View>;
}

function ResearchLedgerV2({ research, actioning, onProcess }: { research: ResearchLeads | null; actioning: boolean; onProcess: (ids?: string[]) => void }) {
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  if (!research) return <View style={styles.empty}><Text style={styles.emptyTitle}>Research intake unavailable</Text><Text style={styles.emptyCopy}>Refresh the operator workspace to load the private source queue.</Text></View>;
  const selectable = research.leads.filter((lead) => lead.status === 'pending');
  const selected = selectable.filter((lead) => selectedIds.includes(lead.id));
  const untriagedIds = selected.filter((lead) => !lead.ai_proposal).map((lead) => lead.id);
  const toggle = (id: string) => setSelectedIds((current) => current.includes(id) ? current.filter((item) => item !== id) : [...current, id]);
  const selectVisible = () => setSelectedIds(selected.length === selectable.length ? [] : selectable.map((lead) => lead.id));
  const sourceLabel = (lead: ResearchLead) => lead.source_name === 'OpenStreetMap' ? 'OpenStreetMap' : lead.source_name;
  return <View style={styles.researchWrap}>
    <View style={styles.researchIntro}><View><Text style={styles.researchTitle}>Source triage</Text><Text style={styles.researchCopy}>Select unprocessed leads for GPT-5.6 triage. After processing, each lead leaves this tab: uncertain leads move to <Text style={styles.researchStrong}>Needs judgment</Text>, approved leads move to the map, and rejected leads move to <Text style={styles.researchStrong}>Rejected</Text>.</Text></View><View style={styles.researchActions}><Pressable style={[styles.secondaryButton, (!selectable.length || actioning) && styles.buttonDisabled]} disabled={!selectable.length || actioning} onPress={selectVisible}><Text style={styles.secondaryButtonText}>{selected.length === selectable.length ? 'Clear visible' : `Select visible (${selectable.length})`}</Text></Pressable><Pressable style={[styles.processButton, (actioning || (selected.length > 0 && !untriagedIds.length) || (!selected.length && !research.stats.remaining)) && styles.buttonDisabled]} disabled={actioning || (selected.length > 0 && !untriagedIds.length) || (!selected.length && !research.stats.remaining)} onPress={() => { onProcess(selected.length ? untriagedIds : undefined); setSelectedIds([]); }}><Text style={styles.processButtonText}>{actioning ? 'Working…' : untriagedIds.length ? `Process selected (${untriagedIds.length})` : 'Process next 100'}</Text></Pressable></View></View>
    <View style={styles.researchStats}><MiniStat value={research.stats.total.toLocaleString()} label="awaiting GPT triage" /><MiniStat value={(research.stats.published || 0).toLocaleString()} label="graduated to map" /><MiniStat value={research.stats.rejected.toLocaleString()} label="rejected" /></View>
    <View style={styles.researchTable}><View style={styles.researchColumns}><Text style={[styles.columnLabel, styles.researchSelect]}>SELECT</Text><Text style={[styles.columnLabel, styles.researchName]}>LEAD</Text><Text style={[styles.columnLabel, styles.researchSource]}>SOURCE</Text><Text style={[styles.columnLabel, styles.researchRoute]}>GPT ROUTE</Text><Text style={[styles.columnLabel, styles.researchConfidence]}>CONF.</Text></View>{research.leads.map((lead) => { const selectableLead = lead.status === 'pending'; const checked = selectedIds.includes(lead.id); return <View key={lead.id} style={styles.researchRow}><Pressable disabled={!selectableLead} onPress={() => toggle(lead.id)} style={[styles.checkBox, checked && styles.checkBoxActive, !selectableLead && styles.checkBoxDisabled]}><Text style={styles.checkText}>{checked ? '✓' : ''}</Text></Pressable><View style={styles.researchName}><Text numberOfLines={1} style={styles.recordName}>{lead.name}</Text>{lead.address ? <Text numberOfLines={1} style={styles.recordSub}>{lead.address}</Text> : <View style={styles.missingAddressRow}><Text style={styles.missingAddress}>MISSING ADDRESS</Text><Text numberOfLines={1} style={styles.recordSub}>{lead.venue_type}</Text></View>}</View><Pressable style={styles.researchSource} disabled={!lead.source_url} onPress={() => lead.source_url && Linking.openURL(lead.source_url)}><Text numberOfLines={1} style={[styles.sourceLink, !lead.source_url && styles.sourcePlain]}>{sourceLabel(lead)}{lead.source_url ? ' ↗' : ''}</Text><Text numberOfLines={1} style={styles.sourceLicense}>{lead.source_license || 'source retained'}</Text></Pressable><View style={styles.researchRoute}><Text style={styles.routeText}>{lead.ai_proposal?.route === 'evidence_collection' ? 'Collect evidence' : lead.ai_proposal?.route === 'needs_judgment' ? 'Needs judgment' : lead.ai_proposal?.route === 'reject' ? 'Rejected' : 'Untriaged'}</Text><Text numberOfLines={1} style={styles.routeReason}>{lead.ai_proposal?.reason || 'Ready for GPT triage'}</Text></View><Text style={styles.researchConfidence}>{lead.ai_proposal?.confidence != null ? `${Math.round(lead.ai_proposal.confidence * 100)}%` : '—'}</Text></View>; })}</View>
  </View>;
}

function ChangeSet({ row }: { row: OperatorSubmission }) {
  const tags = row.aiReview?.proposed_tags || [];
  const publicChanges = row.entityType === 'research_lead'
    ? [['New map record', 'Name, address, category, and source attribution'], ['Access', 'Confirm access when you arrive'], ['Description', 'Operator-approved research lead after GPT source triage'], ['Tags', tags.length ? tags.map(displayTag).join(', ') : 'research lead']]
    : row.entityType === 'place_suggestion'
    ? [['New map record', 'Name, address, category, and location'], ['Access', row.accessDetail || 'Check with staff'], ['Description', row.aiReview?.description || row.note || 'Community-submitted details'], ['Tags', tags.length ? tags.map(displayTag).join(', ') : 'No tags proposed'], ...(row.photoUrl ? [['Photo', 'Approved restroom photo']] : [])]
    : [...(row.accessDetail ? [['Access', row.accessDetail]] : []), ...(tags.length ? [['Tags', tags.map(displayTag).join(', ')]] : []), ...(row.photoUrl ? [['Photo', 'Approved restroom photo']] : [])];
  const unchanged = row.entityType === 'research_lead'
    ? ['Hours remain “Check posted hours”.', 'No restroom photo is added.', 'The record is labeled as a research lead, not city verified.']
    : row.entityType === 'place_suggestion'
    ? ['Hours remain “Check posted hours”.', ...(!row.photoUrl ? ['No public photo is added.'] : []), 'Cleanliness is not published from this submission.']
    : ['Name, location, category, and hours stay unchanged.', 'Existing public description stays unchanged.', ...(!row.photoUrl ? ['No public photo is added.'] : []), 'Cleanliness stays private moderation evidence.'];
  return <View style={styles.changeSet}><View style={styles.changeColumn}><Text style={styles.changeHeading}>WILL {row.entityType === 'place_suggestion' ? 'PUBLISH' : 'UPDATE'}</Text>{publicChanges.length ? publicChanges.map(([field, value]) => <View key={field} style={styles.changeRow}><Text style={styles.changeField}>{field}</Text><Text style={styles.changeValue}>{value}</Text></View>) : <Text style={styles.unchangedText}>No structured public fields were proposed.</Text>}</View><View style={styles.unchangedColumn}><Text style={styles.changeHeading}>WILL NOT CHANGE</Text>{unchanged.map((value) => <Text key={value} style={styles.unchangedText}>• {value}</Text>)}</View></View>;
}

function DetailDrawerV2({ row, onClose, onReview, actioning }: { row: OperatorSubmission; onClose: () => void; onReview: (action: 'approve' | 'reject' | 'edit_and_requeue', note?: string) => void; actioning: boolean }) {
  const [note, setNote] = useState(row.note);
  const canRequeue = row.status === 'rejected' || row.aiReview?.decision === 'reject';
  const pending = row.status === 'pending';
  const outcome = row.status === 'rejected' ? rejectionKind(row) : row.status === 'approved' ? row.aiReview?.operator_actions?.some((action) => action.actor === 'autopilot') ? 'GPT autopublished' : 'Operator approved' : decisionLabel(row.aiReview?.decision || null);
  return <View style={styles.drawerScrim}><Pressable style={StyleSheet.absoluteFill} onPress={onClose} /><ScrollView style={styles.drawer} contentContainerStyle={styles.drawerContent}><View style={styles.drawerTop}><View><Text style={styles.drawerType}>{entityLabel(row.entityType)}</Text><Text style={styles.drawerTitle}>{row.title}</Text><Text style={styles.drawerSub}>{row.subtitle}</Text>{row.sourceUrl ? <Pressable onPress={() => Linking.openURL(row.sourceUrl!)}><Text style={styles.sourceLink}>{row.sourceName || 'Source'} ↗</Text></Pressable> : null}</View><Pressable onPress={onClose} style={styles.closeButton}><Text style={styles.closeButtonText}>×</Text></Pressable></View><View style={styles.detailMeta}><View style={styles.detailMetric}><Text style={styles.detailMetricValue}>{row.aiReview?.confidence != null ? `${Math.round(row.aiReview.confidence * 100)}%` : '—'}</Text><Text style={styles.detailMetricLabel}>GPT confidence</Text></View><View style={styles.detailMetric}><Text style={styles.detailMetricValue}>{outcome}</Text><Text style={styles.detailMetricLabel}>Current outcome</Text></View></View><ChangeSet row={row} /><View style={styles.evidenceGrid}><View style={styles.evidenceText}><Text style={styles.evidenceLabel}>GPT REASON</Text><Text style={styles.evidenceCopy}>{row.aiReview?.reason || row.aiReviewError || 'GPT has not returned an explanation yet.'}</Text>{row.aiReview?.concerns?.length ? <><Text style={styles.evidenceLabel}>CONCERNS</Text><Text style={styles.evidenceCopy}>{row.aiReview.concerns.join(' · ')}</Text></> : null}</View><View style={styles.photoFrame}>{row.photoUrl ? <Image source={{ uri: row.photoUrl }} style={styles.photo} resizeMode="cover" accessibilityLabel="Private contributor evidence" /> : <Text style={styles.photoEmpty}>{row.entityType === 'research_lead' ? 'Source metadata only' : 'No contributor photo'}</Text>}</View></View>{tags(row).length ? <View style={styles.tagRow}>{tags(row).map((tag) => <View key={tag} style={styles.tag}><Text style={styles.tagText}>{displayTag(tag)}</Text></View>)}</View> : null}{canRequeue ? <View style={styles.editBlock}><Text style={styles.evidenceLabel}>AMEND AND RE-RUN GPT</Text><TextInput value={note} onChangeText={setNote} style={styles.noteInput} multiline placeholder="Correct the submitted detail before re-running" placeholderTextColor="#78847C" /><Pressable style={styles.secondaryButton} onPress={() => onReview('edit_and_requeue', note)} disabled={actioning}><Text style={styles.secondaryButtonText}>{actioning ? 'Saving…' : 'Save & re-run GPT review'}</Text></Pressable></View> : null}{pending && !canRequeue ? <View style={styles.reviewActions}><Pressable style={styles.rejectButton} onPress={() => onReview('reject')} disabled={actioning}><Text style={styles.rejectText}>Reject</Text></Pressable><Pressable style={styles.primaryButton} onPress={() => onReview('approve')} disabled={actioning}><Text style={styles.primaryButtonText}>{actioning ? 'Saving…' : row.entityType === 'restroom_update' ? 'Approve update' : 'Publish to map'}</Text></Pressable></View> : null}{!pending && !canRequeue ? <View style={styles.finalState}><Text style={styles.finalStateText}>This record is approved and its listed changes are live.</Text></View> : null}</ScrollView></View>;
}

function tags(row: OperatorSubmission) { return row.aiReview?.proposed_tags || []; }

function TraceDrawerV2({ rows, onClose }: { rows: OperatorSubmission[]; onClose: () => void }) {
  const events = useMemo(() => rows.flatMap((row) => {
    const item = [{ at: row.createdAt, actor: 'User', event: 'Submitted', record: row.title, detail: entityLabel(row.entityType) }];
    item.push({ at: row.createdAt, actor: 'System', event: 'Queued GPT review', record: row.title, detail: 'Private evidence pipeline' });
    if (row.aiReviewedAt) item.push({ at: row.aiReviewedAt, actor: 'OpenAI', event: 'GPT-5.6 classified', record: row.title, detail: `${decisionLabel(row.aiReview?.decision || null)}${row.aiReview?.confidence != null ? ` · ${Math.round(row.aiReview.confidence * 100)}%` : ''}` });
    (row.aiReview?.operator_actions || []).forEach((action) => item.push({ at: action.at, actor: action.actor === 'autopilot' ? 'System' : 'Operator', event: action.action.replaceAll('_', ' '), record: row.title, detail: action.actor === 'autopilot' ? 'Autopilot policy satisfied' : action.applied_fields?.length ? `Applied: ${action.applied_fields.join(', ')}` : entityLabel(row.entityType) }));
    return item;
  }).sort((a, b) => new Date(b.at).getTime() - new Date(a.at).getTime()), [rows]);
  const exportCsv = () => { if (Platform.OS !== 'web' || typeof document === 'undefined') return; const csv = ['time,actor,event,record,details', ...events.map((event) => [event.at, event.actor, event.event, event.record, event.detail].map((value) => `"${String(value).replaceAll('"', '""')}"`).join(','))].join('\n'); const blob = new Blob([csv], { type: 'text/csv;charset=utf-8' }); const url = URL.createObjectURL(blob); const anchor = document.createElement('a'); anchor.href = url; anchor.download = 'relief-activity-trace.csv'; anchor.click(); URL.revokeObjectURL(url); };
  return <View style={styles.drawerScrim}><Pressable style={StyleSheet.absoluteFill} onPress={onClose} /><View style={styles.traceDrawer}><View style={styles.drawerTop}><View><Text style={styles.drawerType}>AUDIT</Text><Text style={styles.drawerTitle}>Activity trace</Text></View><View style={styles.traceActions}><Pressable style={styles.exportButton} onPress={exportCsv}><Text style={styles.exportButtonText}>Export CSV</Text></Pressable><Pressable onPress={onClose} style={styles.closeButton}><Text style={styles.closeButtonText}>×</Text></Pressable></View></View><View style={styles.traceHeader}><Text style={styles.traceColTime}>TIME</Text><Text style={styles.traceColActor}>ACTOR</Text><Text style={styles.traceColEvent}>EVENT</Text><Text style={styles.traceColRecord}>RECORD</Text><Text style={styles.traceColDetail}>DETAILS</Text></View><ScrollView>{events.length ? events.map((event, index) => <View key={`${event.at}-${index}`} style={styles.traceLedgerRow}><Text style={styles.traceColTime}>{dateLabel(event.at)}</Text><View style={styles.traceColActor}><Text style={[styles.actorPill, event.actor === 'OpenAI' && styles.actorOpenAi, event.actor === 'Operator' && styles.actorOperator]}>{event.actor}</Text></View><Text style={styles.traceColEvent}>{event.event}</Text><Text numberOfLines={1} style={styles.traceColRecord}>{event.record}</Text><Text numberOfLines={1} style={styles.traceColDetail}>{event.detail}</Text></View>) : <Text style={styles.emptyCopy}>No recorded activity yet.</Text>}</ScrollView></View></View>;
}

